import sys

def is_repdigit(num):
    if num < 10:
        return True
    digit = num % 10
    num //= 10
    while num > 0:
        if num % 10 != digit:
            return False
        num //= 10
    return True

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    D = list(map(int, input[1:N+1]))

    count = 0
    for month in range(1, N+1):
        for day in range(1, D[month-1]+1):
            if is_repdigit(month * 100 + day):
                count += 1
    print(count)

if __name__ == "__main__":
    main()
